const name = $.input.customerName;
const product = $.input.productName;
const feedback = $.input.customerFeedback;
const sender = $.input.senderName || 'Customer Success Team';
const company = $.input.companyName || 'Our Company';

let prompt = 'You are a customer engagement specialist. Analyze the following customer feedback, determine sentiment, and create a personalized follow-up email.\n\n';
prompt += 'CUSTOMER DATA:\n';
prompt += '- Name: ' + name + '\n';
prompt += '- Product: ' + product + '\n';
prompt += '- Feedback: ' + feedback + '\n';
prompt += '- Sender Name: ' + sender + '\n';
prompt += '- Company: ' + company + '\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '1. Analyze the sentiment (positive, neutral, negative)\n';
prompt += '2. If negative, consider offering a discount or personal follow-up\n';
prompt += '3. Create a warm, personalized email that references their specific feedback\n';
prompt += '4. Keep the email concise (150-250 words)\n';
prompt += '5. Include a clear call-to-action\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "sentiment": "positive|neutral|negative",\n';
prompt += '  "sentimentScore": 0.8,\n';
prompt += '  "offerDiscount": false,\n';
prompt += '  "discountPercent": 0,\n';
prompt += '  "emailSubject": "subject line",\n';
prompt += '  "emailBody": "full HTML email body with <p> tags",\n';
prompt += '  "keyInsights": ["insight1", "insight2"]\n';
prompt += '}';
return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { sentiment: 'unknown', sentimentScore: 0, offerDiscount: false, discountPercent: 0, emailSubject: 'Follow-up on your recent purchase', emailBody: '<p>' + raw + '</p>', keyInsights: [] }; }

const ai = $.steps.parseAI.output;
const name = $.input.customerName;
const email = $.input.customerEmail;

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Marketing Email Sent', emoji: true } });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Customer:*\n' + name },
  { type: 'mrkdwn', text: '*Sentiment:*\n' + (ai.sentiment || 'unknown') + ' (' + (ai.sentimentScore || 0) + ')' }
] });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Email:*\n' + email },
  { type: 'mrkdwn', text: '*Discount Offered:*\n' + (ai.offerDiscount ? ai.discountPercent + '%' : 'No') }
] });
blocks.push({ type: 'divider' });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Subject:* ' + (ai.emailSubject || 'N/A') } });

if (ai.keyInsights && ai.keyInsights.length > 0) {
  let insText = '*Key Insights:*\n';
  ai.keyInsights.slice(0, 4).forEach((ins, i) => { insText += (i + 1) + '. ' + ins + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: insText.slice(0, 1800) } });
}

blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Claude AI + Gmail' }] });

const fallbackText = 'Marketing email sent to ' + name + ' (' + email + ') - Sentiment: ' + (ai.sentiment || 'unknown');
return { blocks, fallbackText };
